import { useState } from 'react';
import { Link } from 'react-router-dom';
import { MapPin, Heart } from 'lucide-react';
import { propertiesData, getFilterOptions } from '../data/propertiesData';
import { useFavorites } from '../context/FavoritesContext';
import { useAuth } from '../context/AuthContext';

const Projects = () => {
  const { isAuthenticated } = useAuth();
  const { isFavorite, toggleFavorite } = useFavorites();
  
  const [filters, setFilters] = useState({
    category: 'All',
    listingType: 'All',
    propertyType: 'All',
    maxPrice: 50000000
  });
  const [searchQuery, setSearchQuery] = useState('');
  const [showMobileFilters, setShowMobileFilters] = useState(false);
  
  const filterOptions = getFilterOptions();
  
  const getFilteredProperties = () => {
    let filtered = propertiesData.filter(property => {
      if (filters.category !== 'All' && property.category !== filters.category) return false;
      if (filters.listingType !== 'All' && property.listingType !== filters.listingType) return false;
      if (filters.propertyType !== 'All' && property.propertyType !== filters.propertyType) return false;
      if (property.price > filters.maxPrice) return false;
      return true;
    });
    
    if (searchQuery.trim() !== '') {
      const query = searchQuery.toLowerCase().trim();
      filtered = filtered.filter(property => 
        property.title.toLowerCase().includes(query) ||
        property.location.toLowerCase().includes(query) ||
        property.description.toLowerCase().includes(query)
      );
    }
    
    return filtered;
  };
  
  const filteredProperties = getFilteredProperties();
  
  const getCurrentPropertyTypes = () => {
    if (filters.category === 'Residential') return filterOptions.propertyTypes.Residential;
    if (filters.category === 'Commercial') return filterOptions.propertyTypes.Commercial;
    return ['All'];
  };
  
  const formatPrice = (price, listingType) => {
    if (listingType === 'Rent') {
      if (price >= 100000) return `₹${(price / 100000).toFixed(1)}L/month`;
      return `₹${price.toLocaleString('en-IN')}/month`;
    }
    if (listingType === 'Lease') {
      if (price >= 100000) return `₹${(price / 100000).toFixed(1)}L/year`;
      return `₹${price.toLocaleString('en-IN')}/year`;
    }
    if (price >= 10000000) return `₹${(price / 10000000).toFixed(2)} Cr`;
    if (price >= 100000) return `₹${(price / 100000).toFixed(1)} Lakhs`;
    return `₹${price.toLocaleString('en-IN')}`;
  };
  
  const getListingTypeColor = (type) => {
    switch(type) {
      case 'Sale': return 'bg-green-600';
      case 'Rent': return 'bg-blue-600';
      case 'Lease': return 'bg-purple-600';
      default: return 'bg-gray-600';
    }
  };

  const handleFavoriteClick = (e, property) => {
    e.stopPropagation();
    if (!isAuthenticated) {
      alert('Please login to save favorites');
      return;
    }
    toggleFavorite(property);
  };

  const formatDisplayPrice = (price) => {
    if (price >= 10000000) return `₹${(price / 10000000).toFixed(2)} Cr`;
    if (price >= 100000) return `₹${(price / 100000).toFixed(1)} Lakhs`;
    if (price >= 1000) return `₹${(price / 1000).toFixed(0)}K`;
    return `₹${price}`;
  };

  return (
    <div className="bg-[#0a0a0a] min-h-screen pt-24 pb-16">
      <div className="container-custom">
        <div className="text-center mb-8">
          <h1 className="text-3xl md:text-4xl font-bold text-white mb-2">Find Your Dream Property</h1>
          <p className="text-white/50 text-sm">Discover residential & commercial properties in Nashik</p>
        </div>
        
        {/* Search Bar */}
        <div className="mb-6">
          <div className="relative max-w-md mx-auto">
            <input
              type="text"
              placeholder="Search by property name, location..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full px-4 py-2 bg-[#111111] border border-gray-700 rounded-lg focus:outline-none focus:border-[#c8a45e] text-white placeholder:text-white/30"
            />
          </div>
        </div>
        
        {/* Filter Toggle */}
        <div className="lg:hidden mb-4">
          <button
            onClick={() => setShowMobileFilters(!showMobileFilters)}
            className="w-full bg-[#111111] border border-gray-700 rounded-lg py-2 text-white/70 text-sm"
          >
            {showMobileFilters ? 'Hide Filters' : 'Show Filters'}
          </button>
        </div>
        
        {/* Filters */}
        <div className={`bg-[#111111] rounded-xl p-4 mb-6 ${showMobileFilters ? 'block' : 'hidden lg:block'}`}>
          <div className="flex flex-wrap gap-3">
            <select
              value={filters.category}
              onChange={(e) => setFilters({...filters, category: e.target.value, propertyType: 'All'})}
              className="px-3 py-1.5 bg-[#0a0a0a] border border-gray-700 rounded-lg text-white/70 text-sm"
            >
              {filterOptions.categories.map(cat => <option key={cat} value={cat}>{cat}</option>)}
            </select>
            
            <select
              value={filters.listingType}
              onChange={(e) => setFilters({...filters, listingType: e.target.value})}
              className="px-3 py-1.5 bg-[#0a0a0a] border border-gray-700 rounded-lg text-white/70 text-sm"
            >
              {filterOptions.listingTypes.map(type => <option key={type} value={type}>{type}</option>)}
            </select>
            
            {(filters.category === 'Residential' || filters.category === 'Commercial') && (
              <select
                value={filters.propertyType}
                onChange={(e) => setFilters({...filters, propertyType: e.target.value})}
                className="px-3 py-1.5 bg-[#0a0a0a] border border-gray-700 rounded-lg text-white/70 text-sm"
              >
                {getCurrentPropertyTypes().map(type => <option key={type} value={type}>{type}</option>)}
              </select>
            )}
            
            <div className="flex items-center gap-2">
              <span className="text-white/50 text-xs">Max:</span>
              <input
                type="range"
                min="5000"
                max="50000000"
                step="50000"
                value={filters.maxPrice}
                onChange={(e) => setFilters({...filters, maxPrice: parseInt(e.target.value)})}
                className="w-32"
              />
              <span className="text-[#c8a45e] text-xs font-medium">{formatDisplayPrice(filters.maxPrice)}</span>
            </div>
            
            <button
              onClick={() => setFilters({ category: 'All', listingType: 'All', propertyType: 'All', maxPrice: 50000000 })}
              className="px-3 py-1.5 bg-gray-800 text-white/60 rounded-lg text-xs hover:bg-gray-700"
            >
              Reset
            </button>
          </div>
        </div>
        
        <div className="mb-4">
          <p className="text-white/50 text-sm">{filteredProperties.length} properties found</p>
        </div>
        
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredProperties.map((property) => (
            <div key={property.id} className="bg-[#111111] rounded-xl overflow-hidden hover:shadow-xl transition group">
              <div className="relative h-48 overflow-hidden">
                <img 
                  src={property.images[0]} 
                  alt={property.title}
                  className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110"
                />
                <button
                  onClick={(e) => handleFavoriteClick(e, property)}
                  className="absolute top-3 right-3 p-1.5 bg-black/50 rounded-full hover:bg-black/70 transition"
                >
                  <Heart size={18} className={isFavorite(property.id) ? 'text-red-500 fill-red-500' : 'text-white'} />
                </button>
                <div className="absolute top-3 left-3">
                  <span className={`${getListingTypeColor(property.listingType)} text-white text-xs px-2 py-1 rounded`}>
                    {property.listingType}
                  </span>
                </div>
                <div className="absolute bottom-3 left-3">
                  <span className="bg-[#c8a45e]/20 text-[#c8a45e] text-xs px-2 py-1 rounded">{property.propertyType}</span>
                </div>
              </div>
              
              <div className="p-4">
                <h3 className="text-lg font-bold text-white mb-1">{property.title}</h3>
                <p className="text-white/50 text-sm mb-2 flex items-center gap-1"><MapPin size={12} /> {property.location}</p>
                <p className="text-[#c8a45e] font-bold text-lg">{formatPrice(property.price, property.listingType)}</p>
                <div className="flex gap-3 mt-2 text-white/40 text-xs">
                  {property.bedrooms > 0 && <span>🛏️ {property.bedrooms} BHK</span>}
                  <span>📐 {property.area_sqft} sq.ft</span>
                </div>
                <Link to={`/property/${property.id}`}>
                  <button className="w-full mt-3 border border-gray-700 py-2 rounded-md hover:bg-[#c8a45e] hover:text-black transition text-white/70 text-sm">
                    View Details
                  </button>
                </Link>
              </div>
            </div>
          ))}
        </div>
        
        {filteredProperties.length === 0 && (
          <div className="text-center py-12">
            <p className="text-white/50">No properties match your filters.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Projects;
